// ─── AdminOrderDispatchImages ─────────────────────────────────────────────────
function AdminOrderDispatchImages({ orderId, secret }: { orderId: string; secret: string }) {
  const [images, setImages] = React.useState<{ id: string; filename: string; uploadedAt: string; ocrOrderCode?: string | null; ocrUsername?: string | null }[] | null>(null);
  const [loadedData, setLoadedData] = React.useState<Record<string, string>>({});
  const [lightbox, setLightbox] = React.useState<string | null>(null);
  const [deleting, setDeleting] = React.useState<string | null>(null);

  React.useEffect(() => {
    fetch(`/api/admin/orders/${orderId}/dispatch-images`, { headers: { "x-admin-secret": secret }, credentials: "omit" })
      .then(r => r.ok ? r.json() : [])
      .then(d => setImages(Array.isArray(d) ? d : []))
      .catch(() => setImages([]));
  }, [orderId, secret]);

  const loadImage = (imgId: string) => {
    if (loadedData[imgId]) { setLightbox(loadedData[imgId]); return; }
    fetch(`/api/admin/dispatch/images/${imgId}`, { headers: { "x-admin-secret": secret }, credentials: "omit" })
      .then(r => r.json())
      .then(d => { if (d.imageData) { setLoadedData(prev => ({ ...prev, [imgId]: d.imageData })); setLightbox(d.imageData); } })
      .catch(() => {});
  };

  const deleteImage = async (imgId: string) => {
    if (!confirm("Remove this dispatch photo?")) return;
    setDeleting(imgId);
    await fetch(`/api/admin/dispatch/images/${imgId}`, { method: "DELETE", headers: { "x-admin-secret": secret }, credentials: "omit" }).catch(() => {});
    setImages(prev => prev ? prev.filter(i => i.id !== imgId) : prev);
    setDeleting(null);
  };

  if (!images || images.length === 0) return null;

  return (
    <div className="px-3 py-2 border-t border-indigo-100 bg-indigo-50/40">
      <p className="text-[10px] font-bold text-indigo-600 mb-2 uppercase tracking-wide">Dispatch Photos ({images.length})</p>
      <div className="flex flex-wrap gap-2">
        {images.map(img => (
          <div key={img.id} className="relative group">
            <button
              onClick={() => loadImage(img.id)}
              className="w-16 h-16 rounded-lg border border-indigo-200 bg-white overflow-hidden flex items-center justify-center hover:border-indigo-400 transition-colors cursor-zoom-in"
              title={img.filename}
            >
              {loadedData[img.id] ? (
                <img src={loadedData[img.id]} alt={img.filename} className="w-full h-full object-cover" />
              ) : (
                <span className="text-[9px] text-indigo-400 font-medium text-center px-1 leading-tight">Click to view</span>
              )}
            </button>
            <button
              onClick={() => deleteImage(img.id)}
              disabled={deleting === img.id}
              className="absolute -top-1 -right-1 w-4 h-4 rounded-full bg-red-500 text-white flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-600"
            >
              <span className="text-[9px] font-bold">×</span>
            </button>
          </div>
        ))}
      </div>
      {lightbox && (
        <div className="fixed inset-0 z-50 bg-black/80 flex items-center justify-center p-4" onClick={() => setLightbox(null)}>
          <img src={lightbox} alt="Dispatch photo" className="max-w-full max-h-[90vh] rounded-xl object-contain" onClick={e => e.stopPropagation()} />
          <button className="absolute top-4 right-4 text-white hover:text-white/70" onClick={() => setLightbox(null)}><span className="text-2xl font-bold">×</span></button>
        </div>
      )}
    </div>
  );
}

