function normalizeCountry(c: string): string {
  if (!c) return c;
  return COUNTRY_NORM[c.toLowerCase().trim()] ?? c;
}

function MultiCountrySelect({ options, selected, onChange, size = "sm" }: {
  options: string[];
  selected: string[];
  onChange: (v: string[]) => void;
  size?: "sm" | "md";
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, [open]);
  const toggle = (c: string) =>
    onChange(selected.includes(c) ? selected.filter(x => x !== c) : [...selected, c]);
  const label = selected.length === 0 ? "All Countries" : selected.length === 1 ? selected[0] : `${selected.length} Countries`;
  const btnCls = size === "md"
    ? "h-11 rounded-xl border border-input bg-background px-3 text-sm"
    : "h-9 rounded-lg border border-input bg-background px-3 text-xs";
  return (
    <div ref={ref} className="relative">
      <button type="button" onClick={() => setOpen(o => !o)}
        className={cn(btnCls, "font-medium text-foreground flex items-center gap-1.5 min-w-[140px]")}>
        {selected.length > 0 && (
          <span className="w-4 h-4 rounded-full bg-blue-600 text-white text-[9px] font-black flex items-center justify-center shrink-0">
            {selected.length}
          </span>
        )}
        <span className="flex-1 text-left truncate">{label}</span>
        <ChevronDown className="w-3.5 h-3.5 shrink-0 text-muted-foreground" />
      </button>
      {open && (
        <div className="absolute z-50 top-full mt-1 left-0 bg-white dark:bg-slate-900 border border-border rounded-xl shadow-lg py-1 min-w-[170px] max-h-60 overflow-y-auto">
          <button type="button" onClick={() => onChange([])}
            className="w-full px-3 py-1.5 text-xs text-left flex items-center gap-2 hover:bg-muted/50">
            <span className={cn("w-4 h-4 rounded border flex items-center justify-center shrink-0",
              selected.length === 0 ? "bg-blue-600 border-blue-600" : "border-input")}>
              {selected.length === 0 && <Check className="w-2.5 h-2.5 text-white" />}
            </span>
            All Countries
          </button>
          {options.map(c => (
            <button key={c} type="button" onClick={() => toggle(c)}
              className="w-full px-3 py-1.5 text-xs text-left flex items-center gap-2 hover:bg-muted/50">
              <span className={cn("w-4 h-4 rounded border flex items-center justify-center shrink-0",
                selected.includes(c) ? "bg-blue-600 border-blue-600" : "border-input")}>
                {selected.includes(c) && <Check className="w-2.5 h-2.5 text-white" />}
              </span>
              {c}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function ProductSearchDropdown({
  value,
  onChange,
  options,
  placeholder = "Search...",
  inputClassName,
}: {
  value: string;
  onChange: (v: string) => void;
  options: string[];
  placeholder?: string;
  inputClassName?: string;
}) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState(value);
  const [panelStyle, setPanelStyle] = useState<React.CSSProperties>({});
  const inputRef = useRef<HTMLInputElement>(null);
  const panelRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setQuery(value); }, [value]);

  const reposition = useCallback(() => {
    if (!inputRef.current) return;
    const r = inputRef.current.getBoundingClientRect();
    setPanelStyle({
      position: "fixed",
      top: r.bottom + 4,
      left: r.left,
      width: r.width,
      zIndex: 9999,
    });
  }, []);

  useEffect(() => {
    if (!open) return;
    reposition();
    const handler = (e: MouseEvent) => {
      const target = e.target as Node;
      if (
        inputRef.current && !inputRef.current.contains(target) &&
        panelRef.current && !panelRef.current.contains(target)
      ) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    window.addEventListener("scroll", reposition, true);
    window.addEventListener("resize", reposition);
    return () => {
      document.removeEventListener("mousedown", handler);
      window.removeEventListener("scroll", reposition, true);
      window.removeEventListener("resize", reposition);
    };
  }, [open, reposition]);

  const filtered = useMemo(() => {
    const q = query.toLowerCase().trim();
    if (!q) return options.slice(0, 100);
    return options.filter(o => o.toLowerCase().includes(q)).slice(0, 100);
  }, [query, options]);

  const handleSelect = (name: string) => {
    onChange(name);
    setQuery(name);
    setOpen(false);
  };

  const handleChange = (v: string) => {
    setQuery(v);
    onChange(v);
    setOpen(true);
  };

  return (
    <div className="relative w-full">
      <input
        ref={inputRef}
        type="text"
        value={query}
        onChange={e => handleChange(e.target.value)}
        onFocus={() => { reposition(); setOpen(true); }}
        onKeyDown={e => { if (e.key === "Escape") setOpen(false); }}
        placeholder={placeholder}
        className={cn(
          "flex w-full rounded-md border border-input bg-background px-3 py-1 text-sm shadow-sm transition-colors placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring",
          inputClassName ?? "h-9"
        )}
      />
      {open && filtered.length > 0 && createPortal(
        <div
          ref={panelRef}
          style={panelStyle}
          className="bg-white dark:bg-slate-900 border border-border rounded-xl shadow-xl py-1 max-h-64 overflow-y-auto"
        >
          {filtered.map(name => (
            <button
              key={name}
              type="button"
              onMouseDown={e => e.preventDefault()}
              onClick={() => handleSelect(name)}
              className="w-full px-3 py-1.5 text-xs text-left hover:bg-muted/60 truncate"
            >
              {name}
            </button>
          ))}
        </div>,
        document.body
      )}
    </div>
  );
}

