  lookup_blocked:            { label: "Login Blocked",       kind: "login",  color: "#dc2626", bgClass: "bg-red-50 border-red-200" },
  account_login:             { label: "Account Login",       kind: "login",  color: "#16a34a", bgClass: "bg-green-50 border-green-200" },
  account_login_failed:      { label: "Account Login Failed",kind: "login",  color: "#dc2626", bgClass: "bg-red-50 border-red-200" },
  account_order_login:       { label: "Order Code Login",    kind: "login",  color: "#0891b2", bgClass: "bg-orange-50 border-orange-200" },
  account_signup:            { label: "Account Created",     kind: "login",  color: "#F24908", bgClass: "bg-violet-50 border-violet-200" },
  pin_claimed:               { label: "PIN Claimed",         kind: "login",  color: "#0369a1", bgClass: "bg-sky-50 border-sky-200" },
  order_created:             { label: "Order Created",       kind: "create", color: "#0891b2", bgClass: "bg-orange-50 border-orange-200" },
