const AUDIT_FILTERS = [
  { id: "all", label: "All" },
  { id: "deletions", label: "Deletions" },
  { id: "edits", label: "Edits" },
  { id: "logins", label: "Logins" },
  { id: "payments", label: "Payments" },
];

function DiffRow({ label, before, after }: { label: string; before: string | null; after: string | null }) {
  const changed = before !== after;
  return (
    <div className={`text-xs rounded-lg px-3 py-2 ${changed ? "bg-amber-50 border border-amber-200" : "bg-gray-50 border border-gray-100"}`}>
      <span className="font-semibold text-gray-600 mr-2">{label}:</span>
      {changed ? (
        <span>
          <span className="line-through text-red-500">{before ?? "—"}</span>
          <span className="mx-1 text-gray-400">→</span>
          <span className="text-green-700 font-medium">{after ?? "—"}</span>
        </span>
      ) : (
        <span className="text-gray-500">{after ?? "—"} <span className="text-gray-300">(unchanged)</span></span>
      )}
    </div>
  );
}

function AuditDiff({ log }: { log: any }) {
  const meta = log.metadata ?? {};
  const before = meta.before ?? {};
  const after = meta.after ?? {};
  const action = log.action as string;

  if (action === "order_deleted_by_admin" || action === "order_deleted_by_customer") {
    const snap = meta.snapshot ?? {};
    const items: any[] = snap.lineItems ?? [];
    return (
      <div className="mt-2 space-y-1.5">
        <p className="text-xs font-semibold text-red-700 mb-1">Full snapshot at deletion:</p>
        <div className="grid grid-cols-2 gap-1">
          {meta.status && (
            <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
              <span className="text-gray-500">Status:</span> <span className="font-semibold">{meta.status}</span>
            </div>
          )}
          {snap.deliveryMethod && (
            <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
              <span className="text-gray-500">Delivery:</span> <span className="font-semibold">{snap.deliveryMethod}</span>
            </div>
          )}
          {snap.grandTotal != null && (
            <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
              <span className="text-gray-500">Total:</span> <span className="font-semibold">${Number(snap.grandTotal).toFixed(2)}</span>
            </div>
          )}
          {snap.productSubtotal != null && (
            <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
              <span className="text-gray-500">Subtotal:</span> <span className="font-semibold">${Number(snap.productSubtotal).toFixed(2)}</span>
            </div>
          )}
        </div>
        {snap.shippingName && (
          <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
            <span className="text-gray-500">Ship to:</span> <span className="font-semibold">{snap.shippingName}</span>
            {snap.shippingAddress && <span className="text-gray-500"> — {snap.shippingAddress}</span>}
          </div>
        )}
        {snap.notes && (
          <div className="text-xs bg-white/60 rounded px-2 py-1 border border-red-100">
            <span className="text-gray-500">Notes:</span> {snap.notes}
          </div>
        )}
        {items.length > 0 && (
          <div>
            <p className="text-[11px] font-semibold text-gray-500 mb-1">Items ({items.length}):</p>
            <div className="space-y-1">
              {items.map((li: any, i: number) => {
                const qty = parseFloat(li.quantity);
                const unitP = parseFloat(li.unitPrice);
                const lineT = parseFloat(li.lineTotal ?? li.line_total);
                const computedT = !isNaN(qty) && !isNaN(unitP) ? qty * unitP : NaN;
                return (
                  <div key={i} className="text-xs flex gap-2 items-center bg-white/60 rounded px-2 py-1 border border-red-100">
                    <span className="font-medium text-gray-700 flex-1">{li.productName}</span>
                    <span className="text-gray-400 shrink-0">×{!isNaN(qty) ? qty.toFixed(1).replace(/\.0$/, "") : li.quantity}</span>
                    <span className="text-gray-400 shrink-0">@ {!isNaN(unitP) ? `$${unitP.toFixed(2)}` : "—"}</span>
                    <span className="font-semibold text-gray-600 shrink-0">{!isNaN(lineT) ? `$${lineT.toFixed(2)}` : !isNaN(computedT) ? `$${computedT.toFixed(2)}` : "—"}</span>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    );
  }

  if (action === "username_changed" || action === "customer_renamed") {
    return (
      <div className="mt-2 space-y-1">
        <DiffRow label="Username" before={meta.oldUsername ?? meta.from ?? null} after={meta.newUsername ?? meta.to ?? null} />
      </div>
    );
  }

  if (action === "shipping_address_updated") {
    return (
      <div className="mt-2 space-y-1">
        <DiffRow label="Name" before={before.shippingName} after={after.shippingName} />
        <DiffRow label="Address" before={before.shippingAddress} after={after.shippingAddress} />
      </div>
    );
  }

  if (action === "order_updated_by_admin" || action === "order_updated_by_customer" || action === "admin_update_line_items") {
    const beforeItems: any[] = before.lineItems ?? [];
    const afterItems: any[] = after.lineItems ?? [];
    const changes = meta.changes ?? {};

    return (
      <div className="mt-2 space-y-1.5">
        {before.deliveryMethod !== undefined && <DiffRow label="Delivery" before={before.deliveryMethod} after={after.deliveryMethod} />}
        {before.grandTotal !== undefined && <DiffRow label="Total" before={before.grandTotal != null ? `$${Number(before.grandTotal).toFixed(2)}` : null} after={after.grandTotal != null ? `$${Number(after.grandTotal).toFixed(2)}` : null} />}
        {before.notes !== undefined && <DiffRow label="Notes" before={before.notes} after={after.notes} />}
        {/* Admin PATCH changes */}
        {Object.entries(changes).filter(([k]) => !["grandTotal"].includes(k)).map(([field, val]) => {
          const oldVal = (before as any)[field] ?? null;
          const newVal = String(val);
          if (oldVal === newVal) return null;
          return <DiffRow key={field} label={field} before={oldVal} after={newVal} />;
        })}
        {/* Line items comparison */}
        {(beforeItems.length > 0 || afterItems.length > 0) && (
          <div className="mt-1">
            <p className="text-xs font-semibold text-gray-500 mb-1">Items:</p>
            <div className="space-y-1">
              {afterItems.map((item: any, i: number) => {
                const prev = beforeItems[i];
                return (
                  <div key={i} className="text-xs flex gap-2 items-center">
                    <span className={`font-medium ${prev?.productName !== item.productName ? "text-amber-700" : "text-gray-700"}`}>
                      {item.productName}
                    </span>
                    <span className="text-gray-400">×{Number(item.quantity).toFixed(1).replace(/\.0$/, "")}</span>
                    <span className="text-gray-400">@ ${Number(item.unitPrice).toFixed(2)}</span>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    );
  }

  if (action === "profile_updated") {
    return (
      <div className="mt-2 space-y-1">
        {before.fullName !== undefined && <DiffRow label="Name" before={before.fullName} after={after.fullName} />}
        {before.email !== undefined && <DiffRow label="Email" before={before.email} after={after.email} />}
      </div>
    );
  }

  return null;
}

function ActivityLogTab({ secret }: { secret: string }) {
  const [logs, setLogs] = useState<any[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [eventType, setEventType] = useState("all");
  const [page, setPage] = useState(0);
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const [search, setSearch] = useState("");
  const [searchInput, setSearchInput] = useState("");
  const PAGE_SIZE = 25;

  const fetchLogs = useCallback(async (et: string, pg: number, q: string) => {
    setLoading(true);
    try {
      const params = new URLSearchParams({ eventType: et, page: String(pg), limit: String(PAGE_SIZE) });
      if (q) params.set("q", q);
      const r = await fetch(apiUrl(`/admin/audit-logs?${params}`), { headers: { "x-admin-secret": secret } });
      if (!r.ok) throw new Error("fetch failed");
      const j = await r.json();
      setLogs(j.logs ?? []);
      setTotal(j.total ?? 0);
    } catch { /* ignore */ }
    setLoading(false);
  }, [secret]);

  useEffect(() => { fetchLogs(eventType, page, search); }, [fetchLogs, eventType, page, search]);

  const changeFilter = (et: string) => { setEventType(et); setPage(0); };
  const toggleExpand = (id: string) => setExpanded(prev => { const s = new Set(prev); s.has(id) ? s.delete(id) : s.add(id); return s; });

  const handleSearchSubmit = (e: React.FormEvent) => { e.preventDefault(); setSearch(searchInput.trim()); setPage(0); };
  const clearSearch = () => { setSearch(""); setSearchInput(""); setPage(0); };

  const totalPages = Math.ceil(total / PAGE_SIZE);

  function fmtTime(ts: string) {
    const d = new Date(ts);
    return d.toLocaleString([], { dateStyle: "medium", timeStyle: "short" });
  }

  function actorLabel(log: any): string {
    const m = log.metadata ?? {};
    const actor = m.telegramUsername ?? m.identifier ?? m.oldUsername ?? m.username;
    if (log.action?.includes("admin")) return "Admin";
    if (actor) return actor;
    if (log.ip) return log.ip;
    return "—";
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between gap-3 flex-wrap">
        <div>
          <h2 className="text-lg font-bold text-foreground">Activity Log</h2>
          <p className="text-sm text-muted-foreground mt-0.5">Order changes, deletions, edits, and logins — newest first</p>
        </div>
        <button onClick={() => fetchLogs(eventType, page, search)} className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-semibold rounded-lg bg-muted text-foreground hover:bg-muted/80 transition-colors">
          <RefreshCw className="w-3.5 h-3.5" /> Refresh
        </button>
      </div>

      {/* Search bar */}
      <form onSubmit={handleSearchSubmit} className="flex items-center gap-2">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-muted-foreground pointer-events-none" />
          <input
            className="w-full pl-8 pr-8 py-2 rounded-xl border border-input bg-background text-sm focus:outline-none focus:ring-2 focus:ring-primary"
            placeholder="Search messages, IPs, actions…"
            value={searchInput}
            onChange={e => setSearchInput(e.target.value)}
          />
          {searchInput && (
            <button type="button" onClick={clearSearch} className="absolute right-2.5 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
              <X className="w-3.5 h-3.5" />
            </button>
          )}
        </div>
        <button type="submit" className="px-4 py-2 rounded-xl bg-slate-800 text-white text-xs font-semibold hover:bg-slate-700 transition-colors">
          Search
        </button>
        {search && (
          <button type="button" onClick={clearSearch} className="px-3 py-2 rounded-xl text-xs font-semibold text-muted-foreground hover:bg-muted transition-colors">
            Clear
          </button>
        )}
      </form>

      {/* Filter pills */}
      <div className="flex gap-1.5 flex-wrap items-center">
        {AUDIT_FILTERS.map(f => {
          const active = eventType === f.id;
          return (
            <button
              key={f.id}
              onClick={() => changeFilter(f.id)}
              className={`px-3 py-1.5 rounded-lg text-xs font-semibold transition-all ${active ? "bg-slate-800 text-white" : "bg-muted text-muted-foreground hover:bg-muted/80"}`}
            >
              {f.label}
            </button>
          );
        })}
        {search && (
          <span className="px-2 py-1 rounded-lg bg-amber-100 text-amber-800 text-xs font-semibold">
            Searching: "{search}"
          </span>
        )}
        <span className="ml-auto text-xs text-muted-foreground self-center">{total.toLocaleString()} entries</span>
      </div>

      {/* Log entries */}
      {loading ? (
        <div className="flex items-center justify-center py-16">
          <Loader2 className="w-6 h-6 animate-spin text-gray-400" />
        </div>
      ) : logs.length === 0 ? (
        <div className="text-center py-16 text-gray-400">
          <Activity className="w-10 h-10 mx-auto mb-3 opacity-40" />
          <p className="font-medium">No events found</p>
          <p className="text-sm mt-1">Events will appear here as customers and admins take actions</p>
        </div>
      ) : (
        <div className="space-y-2">
          {logs.map((log: any) => {
            const meta = AUDIT_ACTION_META[log.action] ?? { label: log.action, kind: "other", color: "#64748b", bgClass: "bg-gray-50 border-gray-200" };
            const isDelete = meta.kind === "delete";
            const isExpandable = ["edit", "delete"].includes(meta.kind);
            const isOpen = expanded.has(log.id);
            const code = log.metadata?.code ?? log.metadata?.orderCode ?? null;
            const level: string = log.level ?? "info";
            const levelBadgeClass =
              level === "error" ? "bg-red-100 text-red-700 border border-red-200" :
              level === "warn"  ? "bg-amber-100 text-amber-700 border border-amber-200" :
                                  "bg-blue-100 text-blue-700 border border-blue-200";

            return (
              <div
                key={log.id}
                className={`border rounded-xl transition-all ${isDelete ? "bg-red-50 border-red-200" : meta.bgClass}`}
              >
                <div
                  className={`flex items-start gap-3 px-4 py-3 ${isExpandable ? "cursor-pointer" : ""}`}
                  onClick={() => isExpandable && toggleExpand(log.id)}
                >
                  {/* Dot */}
                  <div className="w-2 h-2 rounded-full mt-1.5 shrink-0" style={{ background: meta.color }} />

                  {/* Content */}
                  <div className="flex-1 min-w-0">
                    <div className="flex flex-wrap items-center gap-x-2 gap-y-1">
                      <span className="text-xs font-bold" style={{ color: meta.color }}>{meta.label}</span>
                      <span className={`text-[10px] font-semibold px-1.5 py-0.5 rounded uppercase tracking-wide ${levelBadgeClass}`}>{level}</span>
                      {code && (
                        <span className="text-xs font-mono font-semibold text-gray-700 bg-white/70 px-1.5 py-0.5 rounded">#{code}</span>
                      )}
                      <span className="text-xs text-gray-500 ml-auto shrink-0">{fmtTime(log.createdAt)}</span>
                    </div>
                    <p className="text-xs text-gray-600 mt-0.5 leading-snug">{log.message}</p>
                    <div className="flex items-center gap-3 mt-1">
                      <span className="text-[10px] text-gray-400">Actor: <span className="font-medium text-gray-600">{actorLabel(log)}</span></span>
                      {log.ip && <span className="text-[10px] text-gray-400">IP: {log.ip}</span>}
                      {(log.city || log.country) && (
                        <span className="text-[10px] text-gray-400">
                          {[log.city, log.country].filter(Boolean).join(", ")}
                        </span>
                      )}
                    </div>

                    {/* Expanded diff */}
                    {isOpen && <AuditDiff log={log} />}
                  </div>

                  {/* Expand chevron */}
                  {isExpandable && (
                    <div className="shrink-0 self-center">
                      {isOpen ? <ChevronUp className="w-3.5 h-3.5 text-gray-400" /> : <ChevronDown className="w-3.5 h-3.5 text-gray-400" />}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-between pt-2">
          <button
            onClick={() => setPage(p => Math.max(0, p - 1))}
            disabled={page === 0}
            className="flex items-center gap-1 px-3 py-1.5 text-xs font-semibold rounded-lg bg-muted text-foreground disabled:opacity-40 hover:bg-muted/80 transition-colors"
          >
            <ChevronLeft className="w-3.5 h-3.5" /> Previous
          </button>
          <span className="text-xs text-muted-foreground">Page {page + 1} of {totalPages}</span>
          <button
            onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))}
            disabled={page >= totalPages - 1}
            className="flex items-center gap-1 px-3 py-1.5 text-xs font-semibold rounded-lg bg-muted text-foreground disabled:opacity-40 hover:bg-muted/80 transition-colors"
          >
            Next <ChevronRight className="w-3.5 h-3.5" />
          </button>
        </div>
      )}
    </div>
  );
}

// ─── Invite Codes Tab ──────────────────────────────────────────────────────

type InviteCodeRow = {
  code: string;
  label: string;
  usageCount: number;
  maxUses: number | null;
  isActive: boolean;
  createdAt: string;
};

function InviteCodesTab({ secret }: { secret: string }) {
  const [codes, setCodes] = useState<InviteCodeRow[]>([]);
  const [requiresInvite, setRequiresInvite] = useState(false);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [newCode, setNewCode] = useState("");
  const [newLabel, setNewLabel] = useState("");
  const [newMaxUses, setNewMaxUses] = useState("");
  const [createError, setCreateError] = useState("");
  const [creating, setCreating] = useState(false);
  const [copied, setCopied] = useState<string | null>(null);

  const h = { "x-admin-secret": secret };

  const fetchCodes = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(apiUrl("/admin/invite-codes"), { headers: h, credentials: "omit" });
      const data = await res.json();
      setCodes(data.codes ?? []);
      setRequiresInvite(data.signupRequiresInvite ?? false);
    } finally {
      setLoading(false);
    }
  }, [secret]);

  useEffect(() => { fetchCodes(); }, [fetchCodes]);

  const toggleRequiresInvite = async () => {
    setSaving(true);
    try {
      const next = !requiresInvite;
      await fetch(apiUrl("/admin/signup-requires-invite"), {
        method: "PATCH", headers: { ...h, "Content-Type": "application/json" }, credentials: "omit",
        body: JSON.stringify({ enabled: next }),
      });
      setRequiresInvite(next);
    } finally {
      setSaving(false);
    }
  };

  const createCode = async (e: React.FormEvent) => {
    e.preventDefault();
    setCreateError("");
    if (!newCode.trim() || !newLabel.trim()) { setCreateError("Code and label are required"); return; }
    setCreating(true);
    try {
      const res = await fetch(apiUrl("/admin/invite-codes"), {
        method: "POST", headers: { ...h, "Content-Type": "application/json" }, credentials: "omit",
        body: JSON.stringify({ code: newCode.trim(), label: newLabel.trim(), maxUses: newMaxUses ? parseInt(newMaxUses) : null }),
      });
      const data = await res.json();
      if (!res.ok) { setCreateError(data.error || "Failed to create code"); return; }
      setCodes(prev => [data, ...prev]);
      setNewCode(""); setNewLabel(""); setNewMaxUses("");
    } catch { setCreateError("Connection error"); }
    finally { setCreating(false); }
  };

  const toggleActive = async (code: string, current: boolean) => {
    const res = await fetch(apiUrl(`/admin/invite-codes/${encodeURIComponent(code)}`), {
      method: "PATCH", headers: { ...h, "Content-Type": "application/json" }, credentials: "omit",
      body: JSON.stringify({ isActive: !current }),
    });
    if (res.ok) {
      setCodes(prev => prev.map(c => c.code === code ? { ...c, isActive: !current } : c));
    }
  };

  const deleteCode = async (code: string) => {
    if (!window.confirm(`Delete invite code "${code}"?`)) return;
    const res = await fetch(apiUrl(`/admin/invite-codes/${encodeURIComponent(code)}`), {
      method: "DELETE", headers: h, credentials: "omit",
    });
    if (res.ok) setCodes(prev => prev.filter(c => c.code !== code));
  };

  const copyCode = (code: string) => {
    navigator.clipboard.writeText(code).then(() => {
      setCopied(code);
      setTimeout(() => setCopied(null), 1500);
    });
  };

  return (
    <div className="space-y-6 p-4 max-w-4xl mx-auto">
      <div>
        <h2 className="text-lg font-bold text-foreground mb-1">Invite Codes</h2>
        <p className="text-sm text-muted-foreground">Track where signups come from. Optionally restrict registration to code-holders only.</p>
      </div>

      {/* Require invite toggle */}
      <Card className="p-4">
        <div className="flex items-center justify-between gap-4">
          <div>
            <p className="text-sm font-semibold text-foreground">Require invite code to sign up</p>
            <p className="text-xs text-muted-foreground mt-0.5">When enabled, new accounts can only be created with a valid, active invite code.</p>
          </div>
          <button
            onClick={toggleRequiresInvite}
            disabled={saving}
            className="shrink-0 flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded-lg transition-all"
            style={{
              background: requiresInvite ? "rgba(239,68,68,0.1)" : "rgba(34,197,94,0.1)",
              color: requiresInvite ? "#dc2626" : "#16a34a",
              border: `1.5px solid ${requiresInvite ? "rgba(239,68,68,0.25)" : "rgba(34,197,94,0.25)"}`,
            }}
          >
            {requiresInvite ? <ToggleRight className="w-4 h-4" /> : <ToggleLeft className="w-4 h-4" />}
            {requiresInvite ? "Required (on)" : "Optional (off)"}
          </button>
        </div>
      </Card>

      {/* Create new code */}
      <Card className="p-4">
        <h3 className="text-sm font-bold text-foreground mb-3 flex items-center gap-2">
          <Plus className="w-4 h-4" /> New Invite Code
        </h3>
        <form onSubmit={createCode} className="space-y-3">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            <div>
              <label className="block text-xs font-semibold text-muted-foreground mb-1 uppercase tracking-wide">Code</label>
              <input
                value={newCode}
                onChange={e => setNewCode(e.target.value.toUpperCase().replace(/\s/g, ""))}
                placeholder="REDDIT2024"
                className="w-full h-9 px-3 rounded-lg text-sm font-mono tracking-widest border bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
              />
            </div>
            <div className="sm:col-span-1">
              <label className="block text-xs font-semibold text-muted-foreground mb-1 uppercase tracking-wide">Label / Source</label>
              <input
                value={newLabel}
                onChange={e => setNewLabel(e.target.value)}
                placeholder="Reddit r/peptides"
                className="w-full h-9 px-3 rounded-lg text-sm border bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
              />
            </div>
            <div>
              <label className="block text-xs font-semibold text-muted-foreground mb-1 uppercase tracking-wide">Max Uses <span className="normal-case font-normal">(blank = unlimited)</span></label>
              <input
                type="number"
                min="1"
                value={newMaxUses}
                onChange={e => setNewMaxUses(e.target.value)}
                placeholder="Unlimited"
                className="w-full h-9 px-3 rounded-lg text-sm border bg-background focus:outline-none focus:ring-2 focus:ring-primary/20"
              />
            </div>
          </div>
          {createError && <p className="text-xs text-red-500">{createError}</p>}
          <button
            type="submit"
            disabled={creating || !newCode.trim() || !newLabel.trim()}
            className="h-9 px-4 rounded-lg text-sm font-semibold text-white flex items-center gap-1.5 disabled:opacity-50 transition-opacity"
            style={{ background: "var(--t-blue-deep, #1B3A7A)" }}
          >
            {creating ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Plus className="w-3.5 h-3.5" />}
            Create Code
          </button>
        </form>
      </Card>

      {/* Codes table */}
      <Card className="overflow-hidden">
        <div className="px-4 py-3 border-b flex items-center justify-between">
          <h3 className="text-sm font-bold text-foreground">All Codes</h3>
          <span className="text-xs text-muted-foreground">{codes.length} total</span>
        </div>
        {loading ? (
          <div className="flex items-center justify-center py-10">
            <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
          </div>
        ) : codes.length === 0 ? (
          <div className="flex flex-col items-center gap-2 py-10 text-muted-foreground">
            <Ticket className="w-8 h-8 opacity-30" />
            <p className="text-sm">No invite codes yet</p>
          </div>
        ) : (
          <div className="divide-y">
            {codes.map(c => (
              <div key={c.code} className={cn("flex items-center gap-3 px-4 py-3", !c.isActive && "opacity-50")}>
                <div className="flex-1 min-w-0 space-y-0.5">
                  <div className="flex items-center gap-2 flex-wrap">
                    <button
                      onClick={() => copyCode(c.code)}
                      className="font-mono text-sm font-bold tracking-widest px-2 py-0.5 rounded bg-muted hover:bg-muted/80 transition-colors flex items-center gap-1.5"
                    >
                      {copied === c.code ? <Check className="w-3 h-3 text-green-600" /> : <Copy className="w-3 h-3 text-muted-foreground" />}
                      {c.code}
                    </button>
                    <span className="text-xs text-muted-foreground truncate">{c.label}</span>
                  </div>
                  <div className="flex items-center gap-3 text-xs text-muted-foreground">
                    <span>
                      <span className="font-semibold text-foreground">{c.usageCount}</span>
                      {c.maxUses !== null ? <> / {c.maxUses} uses</> : " uses"}
                    </span>
                    {c.maxUses !== null && c.usageCount >= c.maxUses && (
                      <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full bg-orange-100 text-orange-700">Limit reached</span>
                    )}
                    <span>{new Date(c.createdAt).toLocaleDateString()}</span>
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <button
                    onClick={() => toggleActive(c.code, c.isActive)}
                    className="text-xs font-semibold px-2 py-1 rounded-lg transition-all"
                    style={{
                      background: c.isActive ? "rgba(34,197,94,0.1)" : "rgba(100,116,139,0.1)",
                      color: c.isActive ? "#16a34a" : "#64748b",
                    }}
                  >
                    {c.isActive ? "Active" : "Inactive"}
                  </button>
                  <button
                    onClick={() => deleteCode(c.code)}
                    className="w-7 h-7 flex items-center justify-center rounded-lg text-muted-foreground hover:text-red-500 hover:bg-red-50 transition-colors"
                  >
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </Card>
    </div>
  );
}

// ── Admin Coupons Tab ─────────────────────────────────────────────────────────
type CouponCode = {
  id: string; code: string; discountType: "percentage" | "fixed";
  discountValue: string; maxUses: number | null; usageCount: number;
  expiresAt: string | null; isActive: boolean; createdAt: string;
};

// ─── CreditLogTab ─────────────────────────────────────────────
interface CreditLogEntry {
  id: number;
  accountUsername: string;
  amount: number;
  reason: string;
  orderCode: string | null;
  orderId: string | null;
  adminUsername: string | null;
  createdAt: string;
}

function CreditLogTab({ secret }: { secret: string }) {
  const [entries, setEntries] = useState<CreditLogEntry[]>([]);
  const [total, setTotal] = useState(0);
  const [loading, setLoading] = useState(false);
  const [searchInput, setSearchInput] = useState("");
  const [searchQuery, setSearchQuery] = useState("");
  const [type, setType] = useState<"all" | "credit" | "debit">("all");
  const [page, setPage] = useState(0);
  const PAGE_SIZE = 50;

  useEffect(() => {
    const t = setTimeout(() => { setSearchQuery(searchInput.trim()); setPage(0); }, 350);
    return () => clearTimeout(t);
  }, [searchInput]);

  const fetchLog = useCallback(async (pg = 0) => {
    setLoading(true);
    try {
      const params = new URLSearchParams({
        limit: String(PAGE_SIZE),
        offset: String(pg * PAGE_SIZE),
        type,
      });
      if (searchQuery) params.set("q", searchQuery);
      const r = await fetch(apiUrl(`/admin/credit-log?${params}`), { headers: { "x-admin-secret": secret } });
      const j = await r.json();
      setEntries(j.transactions ?? []);
      setTotal(j.total ?? 0);
      setPage(pg);
    } catch { /* ignore */ }
    setLoading(false);
  }, [secret, searchQuery, type]);

  useEffect(() => { fetchLog(0); }, [fetchLog]);

  const totalPages = Math.ceil(total / PAGE_SIZE);

  const formatReason = (e: CreditLogEntry) => {
    if (e.orderCode) {
      return e.reason.replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, `#${e.orderCode}`);
    }
    return e.reason;
  };

  const totalCredits  = entries.filter(e => e.amount > 0).reduce((s, e) => s + e.amount, 0);
  const totalDebits   = entries.filter(e => e.amount < 0).reduce((s, e) => s + e.amount, 0);

  return (
    <div className="p-4 space-y-4 max-w-5xl mx-auto">
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div>
          <h2 className="text-lg font-bold">Credit Log</h2>
          <p className="text-xs text-muted-foreground">{total.toLocaleString()} total transactions</p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <div className="flex rounded-xl overflow-hidden border border-border text-xs font-medium">
            {(["all", "credit", "debit"] as const).map(t => (
              <button key={t} onClick={() => { setType(t); setPage(0); }}
                className={cn("px-3 py-1.5 transition-colors capitalize", type === t ? "bg-violet-600 text-white" : "bg-background text-muted-foreground hover:bg-muted")}>
                {t}
              </button>
            ))}
          </div>
          <input
            value={searchInput}
            onChange={e => setSearchInput(e.target.value)}
            placeholder="Search username, reason…"
            className="border border-border rounded-xl px-3 py-1.5 text-xs w-52 bg-background focus:outline-none focus:ring-2 focus:ring-violet-500/30"
          />
          <button onClick={() => fetchLog(page)}
            className="px-3 py-1.5 rounded-xl border border-border text-xs bg-background hover:bg-muted transition-colors">
            Refresh
          </button>
        </div>
      </div>

      {entries.length > 0 && (
        <div className="grid grid-cols-3 gap-3">
          <div className="rounded-xl border border-border bg-green-50 p-3">
            <p className="text-[10px] font-bold text-green-700 uppercase tracking-wider mb-0.5">Credits Added (page)</p>
            <p className="text-lg font-bold text-green-700">+${totalCredits.toLocaleString()}</p>
          </div>
          <div className="rounded-xl border border-border bg-red-50 p-3">
            <p className="text-[10px] font-bold text-red-700 uppercase tracking-wider mb-0.5">Credits Deducted (page)</p>
            <p className="text-lg font-bold text-red-600">${totalDebits.toLocaleString()}</p>
          </div>
          <div className="rounded-xl border border-border bg-muted/50 p-3">
            <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-0.5">Net (page)</p>
            <p className={cn("text-lg font-bold", totalCredits + totalDebits >= 0 ? "text-green-700" : "text-red-600")}>
              {totalCredits + totalDebits >= 0 ? "+" : ""}${(totalCredits + totalDebits).toLocaleString()}
            </p>
          </div>
        </div>
      )}

      {loading ? (
        <div className="flex justify-center py-12"><Loader2 className="w-6 h-6 animate-spin text-violet-500" /></div>
      ) : entries.length === 0 ? (
        <div className="text-center py-12 text-muted-foreground text-sm">No credit transactions found.</div>
      ) : (
        <div className="rounded-xl border border-border overflow-hidden">
          <div className="grid grid-cols-[140px_1fr_80px_90px_90px] bg-muted/50 px-4 py-2 text-[10px] font-bold uppercase tracking-widest text-muted-foreground border-b border-border">
            <span>Member</span>
            <span>Reason</span>
            <span className="text-right">Amount</span>
            <span className="text-right">By</span>
            <span className="text-right">Date</span>
          </div>
          <div className="divide-y divide-border">
            {entries.map(e => (
              <div key={e.id} className="grid grid-cols-[140px_1fr_80px_90px_90px] px-4 py-2.5 items-center hover:bg-muted/30 transition-colors text-xs">
                <span className="font-mono text-violet-700 truncate">{e.accountUsername}</span>
                <span className="text-foreground truncate pr-2">{formatReason(e)}</span>
                <span className={cn("text-right font-bold font-mono", e.amount > 0 ? "text-green-600" : "text-red-500")}>
                  {e.amount > 0 ? "+" : ""}${e.amount}
                </span>
                <span className="text-right text-muted-foreground truncate">{e.adminUsername ?? <span className="text-blue-500">system</span>}</span>
                <span className="text-right text-muted-foreground whitespace-nowrap">
                  {new Date(e.createdAt).toLocaleDateString("en-GB", { day: "2-digit", month: "short" })}
                  <span className="block text-[10px]">{new Date(e.createdAt).toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" })}</span>
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {totalPages > 1 && (
        <div className="flex items-center justify-between text-xs text-muted-foreground">
          <span>Page {page + 1} of {totalPages} · {total.toLocaleString()} total</span>
          <div className="flex gap-2">
            <button disabled={page === 0} onClick={() => fetchLog(page - 1)}
              className="px-3 py-1.5 rounded-xl border border-border disabled:opacity-40 hover:bg-muted transition-colors">← Prev</button>
            <button disabled={page >= totalPages - 1} onClick={() => fetchLog(page + 1)}
              className="px-3 py-1.5 rounded-xl border border-border disabled:opacity-40 hover:bg-muted transition-colors">Next →</button>
          </div>
        </div>
      )}
    </div>
  );
}

function AdminCouponsTab({ secret }: { secret: string }) {
  const [coupons, setCoupons] = useState<CouponCode[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState<CouponCode | null>(null);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({ code: "", discountType: "percentage" as "percentage" | "fixed", discountValue: "", maxUses: "", expiresAt: "", isActive: true });
  const [msg, setMsg] = useState("");

  const load = () => {
    setLoading(true);
    fetch(apiUrl("/admin/coupon-codes"), { headers: { "x-admin-secret": secret } })
      .then(r => r.json())
      .then(data => { setCoupons(data.coupons ?? []); setLoading(false); })
      .catch(() => { setError("Failed to load coupons"); setLoading(false); });
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => {
    setEditing(null);
    setForm({ code: "", discountType: "percentage", discountValue: "", maxUses: "", expiresAt: "", isActive: true });
    setMsg(""); setShowModal(true);
  };
  const openEdit = (c: CouponCode) => {
    setEditing(c);
    setForm({
      code: c.code, discountType: c.discountType,
      discountValue: c.discountValue, maxUses: c.maxUses != null ? String(c.maxUses) : "",
      expiresAt: c.expiresAt ? c.expiresAt.slice(0, 10) : "",
      isActive: c.isActive,
    });
    setMsg(""); setShowModal(true);
  };

  const handleSave = async () => {
    setSaving(true); setMsg("");
    try {
      const url = editing ? apiUrl(`/admin/coupon-codes/${editing.id}`) : apiUrl("/admin/coupon-codes");
      const method = editing ? "PATCH" : "POST";
      const body = {
        code: form.code.trim().toUpperCase(),
        discountType: form.discountType,
        discountValue: parseFloat(form.discountValue),
        maxUses: form.maxUses ? parseInt(form.maxUses) : null,
        expiresAt: form.expiresAt || null,
        isActive: form.isActive,
      };
      const res = await fetch(url, { method, headers: { "Content-Type": "application/json", "x-admin-secret": secret }, body: JSON.stringify(body) });
      const data = await res.json();
      if (!res.ok) { setMsg(data.error ?? "Error"); setSaving(false); return; }
      setMsg(editing ? "Updated ✓" : "Created ✓");
      load(); setSaving(false); setShowModal(false);
    } catch { setMsg("Network error"); setSaving(false); }
  };

  const handleDelete = async (id: string, code: string) => {
    if (!confirm(`Delete coupon ${code}?`)) return;
    await fetch(apiUrl(`/admin/coupon-codes/${id}`), { method: "DELETE", headers: { "x-admin-secret": secret } });
    load();
  };

  const handleToggle = async (c: CouponCode) => {
    await fetch(apiUrl(`/admin/coupon-codes/${c.id}`), {
      method: "PATCH", headers: { "Content-Type": "application/json", "x-admin-secret": secret },
      body: JSON.stringify({ isActive: !c.isActive }),
    });
    load();
  };

  return (
    <div className="p-4 md:p-6 space-y-4">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold tracking-tight">Coupon Codes</h2>
        <Button size="sm" onClick={openCreate} className="gap-1.5"><Plus className="w-4 h-4" />Create Coupon</Button>
      </div>
      {error && <p className="text-sm text-red-600">{error}</p>}
      {loading ? (
        <div className="flex items-center justify-center h-32"><Loader2 className="w-6 h-6 animate-spin text-muted-foreground" /></div>
      ) : coupons.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground text-sm">
          <Ticket className="w-10 h-10 mx-auto mb-3 opacity-30" /><p>No coupon codes yet</p>
        </div>
      ) : (
        <div className="rounded-xl border overflow-x-auto">
          <table className="w-full text-sm">
            <thead><tr className="border-b bg-muted/40 text-left">
              <th className="px-3 py-2 font-medium">Code</th>
              <th className="px-3 py-2 font-medium">Discount</th>
              <th className="px-3 py-2 font-medium">Uses</th>
              <th className="px-3 py-2 font-medium">Expires</th>
              <th className="px-3 py-2 font-medium">Status</th>
              <th className="px-3 py-2 font-medium">Actions</th>
            </tr></thead>
            <tbody>
              {coupons.map(c => (
                <tr key={c.id} className="border-b last:border-0 hover:bg-muted/20">
                  <td className="px-3 py-2 font-mono font-bold">{c.code}</td>
                  <td className="px-3 py-2">
                    {c.discountType === "percentage" ? `${c.discountValue}%` : `$${parseFloat(c.discountValue).toFixed(2)}`}
                  </td>
                  <td className="px-3 py-2 text-muted-foreground">
                    {c.usageCount}{c.maxUses != null ? ` / ${c.maxUses}` : ""}
                  </td>
                  <td className="px-3 py-2 text-muted-foreground">
                    {c.expiresAt ? new Date(c.expiresAt).toLocaleDateString() : "—"}
                  </td>
                  <td className="px-3 py-2">
                    <button onClick={() => handleToggle(c)}
                      className={`text-xs px-2 py-0.5 rounded-full font-medium border ${c.isActive ? "bg-emerald-50 text-emerald-700 border-emerald-200" : "bg-gray-50 text-gray-500 border-gray-200"}`}>
                      {c.isActive ? "Active" : "Inactive"}
                    </button>
                  </td>
                  <td className="px-3 py-2">
                    <div className="flex gap-2">
                      <button onClick={() => openEdit(c)} className="text-xs text-blue-600 hover:underline">Edit</button>
                      <button onClick={() => handleDelete(c.id, c.code)} className="text-xs text-red-500 hover:underline">Delete</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="bg-background rounded-2xl shadow-2xl w-full max-w-md p-6 space-y-4">
            <h3 className="text-lg font-bold">{editing ? "Edit Coupon" : "Create Coupon"}</h3>
            <div className="space-y-3">
              <div>
                <label className="text-xs font-medium text-muted-foreground block mb-1">Code</label>
                <input value={form.code} onChange={e => setForm(f => ({ ...f, code: e.target.value.toUpperCase() }))}
                  placeholder="SAVE10" className="w-full border rounded-lg px-3 py-2 text-sm font-mono uppercase" />
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-medium text-muted-foreground block mb-1">Discount Type</label>
                  <select value={form.discountType} onChange={e => setForm(f => ({ ...f, discountType: e.target.value as "percentage" | "fixed" }))}
                    className="w-full border rounded-lg px-3 py-2 text-sm">
                    <option value="percentage">Percentage (%)</option>
                    <option value="fixed">Fixed ($)</option>
                  </select>
                </div>
                <div>
                  <label className="text-xs font-medium text-muted-foreground block mb-1">Value</label>
                  <input type="number" min="0" step="0.01" value={form.discountValue}
                    onChange={e => setForm(f => ({ ...f, discountValue: e.target.value }))}
                    placeholder={form.discountType === "percentage" ? "10" : "5.00"}
                    className="w-full border rounded-lg px-3 py-2 text-sm" />
                </div>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="text-xs font-medium text-muted-foreground block mb-1">Max Uses (blank = unlimited)</label>
                  <input type="number" min="0" value={form.maxUses}
                    onChange={e => setForm(f => ({ ...f, maxUses: e.target.value }))}
                    placeholder="100" className="w-full border rounded-lg px-3 py-2 text-sm" />
                </div>
                <div>
                  <label className="text-xs font-medium text-muted-foreground block mb-1">Expires</label>
                  <input type="date" value={form.expiresAt}
                    onChange={e => setForm(f => ({ ...f, expiresAt: e.target.value }))}
                    className="w-full border rounded-lg px-3 py-2 text-sm" />
                </div>
              </div>
              <label className="flex items-center gap-2 cursor-pointer">
                <input type="checkbox" checked={form.isActive} onChange={e => setForm(f => ({ ...f, isActive: e.target.checked }))} />
                <span className="text-sm">Active</span>
              </label>
            </div>
            {msg && <p className="text-sm text-center">{msg}</p>}
            <div className="flex gap-3">
              <Button variant="outline" onClick={() => setShowModal(false)} className="flex-1">Cancel</Button>
              <Button onClick={handleSave} disabled={saving} className="flex-1 gap-1">
                {saving && <Loader2 className="w-3 h-3 animate-spin" />}
                {editing ? "Save Changes" : "Create"}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

