type TabOrderCfg = string[];

function DragList<T extends { id: string }>({
  items, setItems, renderItem,
}: {
  items: T[];
  setItems: (v: T[]) => void;
  renderItem: (item: T, dragHandleProps: React.HTMLAttributes<HTMLDivElement>) => React.ReactNode;
}) {
  const dragIdx = useRef<number | null>(null);
  const overIdx = useRef<number | null>(null);
  const [dragging, setDragging] = useState<number | null>(null);
  const [over, setOver] = useState<number | null>(null);

  const onDragStart = (i: number) => { dragIdx.current = i; setDragging(i); };
  const onDragEnter = (i: number) => { overIdx.current = i; setOver(i); };
  const onDragEnd = () => {
    if (dragIdx.current !== null && overIdx.current !== null && dragIdx.current !== overIdx.current) {
      const arr = [...items];
      const [moved] = arr.splice(dragIdx.current, 1);
      arr.splice(overIdx.current, 0, moved);
      setItems(arr);
    }
    dragIdx.current = null; overIdx.current = null;
    setDragging(null); setOver(null);
  };

  return (
    <div className="space-y-2">
      {items.map((item, i) => (
        <div
          key={item.id}
          draggable
          onDragStart={() => onDragStart(i)}
          onDragEnter={() => onDragEnter(i)}
          onDragEnd={onDragEnd}
          onDragOver={e => e.preventDefault()}
          className="transition-all"
          style={{ opacity: dragging === i ? 0.4 : 1, outline: over === i && dragging !== i ? "2px solid #F24908" : "none", borderRadius: 10 }}
        >
          {renderItem(item, {
            className: "cursor-grab active:cursor-grabbing",
            style: { touchAction: "none" },
          })}
        </div>
      ))}
    </div>
  );
}

function DeliveryTipsSection({ secret }: { secret: string }) {
  const [enabled, setEnabled] = useState(true);
  const [items, setItems] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    fetch(apiUrl("/admin/delivery-tips"), { headers: { "x-admin-secret": secret }, credentials: "omit" })
      .then(r => r.json())
      .then(d => { setEnabled(d.enabled); setItems(d.items ?? []); })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, [secret]);

  const save = async () => {
    setSaving(true); setError(""); setSaved(false);
    try {
      const res = await fetch(apiUrl("/admin/delivery-tips"), {
        method: "PATCH",
        headers: { "Content-Type": "application/json", "x-admin-secret": secret },
        credentials: "omit",
        body: JSON.stringify({ enabled, items }),
      });
      if (!res.ok) throw new Error((await res.json()).error || "Save failed");
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
    } catch (e: any) { setError(e.message); }
    finally { setSaving(false); }
  };

  const updateItem = (i: number, val: string) => setItems(prev => prev.map((x, idx) => idx === i ? val : x));
  const removeItem = (i: number) => setItems(prev => prev.filter((_, idx) => idx !== i));
  const addItem = () => setItems(prev => [...prev, ""]);

  return (
    <div className="bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100">
      <div className="px-5 py-4 flex items-center justify-between" style={{ borderBottom: "1px solid #F1F5F9" }}>
        <div className="flex items-center gap-2.5">
          <Package className="w-4 h-4 text-orange-500" />
          <div>
            <h2 className="text-sm font-bold text-slate-800">Delivery Tips</h2>
            <p className="text-xs text-slate-400 mt-0.5">Shown on the address form when customers submit their delivery address</p>
          </div>
        </div>
        <button
          onClick={() => setEnabled(e => !e)}
          className="flex items-center gap-1.5 text-xs font-semibold px-3 py-1.5 rounded-lg transition-colors"
          style={{
            background: enabled ? "rgba(34,197,94,0.1)" : "rgba(148,163,184,0.12)",
            color: enabled ? "#16A34A" : "#94A3B8",
          }}
        >
          {enabled ? <Eye className="w-3.5 h-3.5" /> : <EyeOff className="w-3.5 h-3.5" />}
          {enabled ? "Visible" : "Hidden"}
        </button>
      </div>
      {loading ? (
        <div className="flex items-center justify-center py-8">
          <Loader2 className="w-5 h-5 animate-spin text-slate-300" />
        </div>
      ) : (
        <div className="p-4 space-y-2">
          <p className="text-[11px] text-slate-400 mb-3">Use <span className="font-mono bg-slate-100 px-1 rounded">**word**</span> to bold text, e.g. <span className="font-mono bg-slate-100 px-1 rounded">Use your **full legal name**</span></p>
          {items.map((item, i) => (
            <div key={i} className="flex items-center gap-2">
              <span className="text-slate-300 text-sm font-bold select-none">•</span>
              <input
                value={item}
                onChange={e => updateItem(i, e.target.value)}
                placeholder="Tip text…"
                className="flex-1 text-sm px-3 py-2 rounded-lg border border-slate-200 bg-slate-50 focus:outline-none focus:border-slate-400 focus:bg-white transition-colors"
              />
              <button
                onClick={() => removeItem(i)}
                className="shrink-0 p-1.5 rounded-lg hover:bg-red-50 text-slate-300 hover:text-red-400 transition-colors"
              >
                <X className="w-4 h-4" />
              </button>
            </div>
          ))}
          <button
            onClick={addItem}
            className="flex items-center gap-1.5 text-xs font-semibold px-3 py-2 rounded-lg w-full transition-colors mt-1"
            style={{ background: "rgba(148,163,184,0.1)", color: "#94A3B8" }}
          >
            <Plus className="w-3.5 h-3.5" /> Add tip
          </button>
          {error && <p className="text-xs text-red-500">{error}</p>}
          <div className="pt-2">
            <button
              onClick={save}
              disabled={saving}
              className="flex items-center gap-2 text-sm font-semibold px-4 py-2 rounded-xl text-white transition-all hover:brightness-110 disabled:opacity-60"
              style={{ background: saved ? "#16A34A" : "#334155" }}
            >
              {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : saved ? <Check className="w-4 h-4" /> : <Save className="w-4 h-4" />}
              {saving ? "Saving…" : saved ? "Saved!" : "Save Changes"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

function TelegramConfigSection({ secret }: { secret: string }) {
  const [status, setStatus] = useState<{ tokenSet: boolean; adminChatIdSet: boolean; webhookUrl: string | null } | null>(null);
  const [botToken, setBotToken] = useState("");
  const [adminChatId, setAdminChatId] = useState("");
  const [showToken, setShowToken] = useState(false);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [registering, setRegistering] = useState(false);
  const [saveResult, setSaveResult] = useState<"ok" | "error" | null>(null);
  const [testResult, setTestResult] = useState<{ ok: boolean; msg: string } | null>(null);
  const [registerResult, setRegisterResult] = useState<{ ok: boolean; msg: string } | null>(null);

  const loadStatus = useCallback(() => {
    fetch(apiUrl("/admin/telegram-config"), { headers: { "x-admin-secret": secret }, credentials: "omit" })
      .then(r => r.json())
      .then(d => setStatus(d))
      .catch(() => {});
  }, [secret]);

  useEffect(() => { loadStatus(); }, [loadStatus]);

  const save = async () => {
    setSaving(true); setSaveResult(null);
    try {
      const body: Record<string, string> = {};
      if (botToken.trim()) body.botToken = botToken.trim();
      if (adminChatId.trim()) body.adminChatId = adminChatId.trim();
      const res = await fetch(apiUrl("/admin/telegram-config"), {
        method: "PUT",
        headers: { "Content-Type": "application/json", "x-admin-secret": secret },
        credentials: "omit",
        body: JSON.stringify(body),
      });
      if (!res.ok) throw new Error();
      const d = await res.json();
      setStatus(d);
      setBotToken("");
      setAdminChatId("");
      setSaveResult("ok");
      setTimeout(() => setSaveResult(null), 3000);
    } catch { setSaveResult("error"); }
    finally { setSaving(false); }
  };

  const test = async () => {
    setTesting(true); setTestResult(null);
    try {
      const res = await fetch(apiUrl("/admin/telegram-config/test"), {
        method: "POST",
        headers: { "x-admin-secret": secret },
        credentials: "omit",
      });
      const d = await res.json();
      if (res.ok) setTestResult({ ok: true, msg: "Test message sent! Check your Telegram." });
      else setTestResult({ ok: false, msg: d.error || "Failed to send" });
    } catch { setTestResult({ ok: false, msg: "Network error" }); }
    finally { setTesting(false); }
  };

  const registerWebhook = async () => {
    setRegistering(true); setRegisterResult(null);
    try {
      const res = await fetch(apiUrl("/admin/telegram-config/register-webhook"), {
        method: "POST",
        headers: { "x-admin-secret": secret },
        credentials: "omit",
      });
      const d = await res.json();
      if (res.ok) {
        setRegisterResult({ ok: true, msg: `Webhook registered: ${d.webhookUrl}` });
        loadStatus();
      } else {
        setRegisterResult({ ok: false, msg: d.error || "Failed to register webhook" });
      }
    } catch { setRegisterResult({ ok: false, msg: "Network error" }); }
    finally { setRegistering(false); }
  };

  return (
    <div className="bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100">
      <div className="px-5 py-4 flex items-center gap-2.5" style={{ borderBottom: "1px solid #F1F5F9" }}>
        <MessageSquarePlus className="w-4 h-4" style={{ color: "#229ED9" }} />
        <div>
          <h2 className="text-sm font-bold text-slate-800">Telegram Bot</h2>
          <p className="text-xs text-slate-400 mt-0.5">Connect your bot to send order notifications to customers and yourself</p>
        </div>
      </div>
      <div className="p-4 space-y-4">
        <div>
          <div className="flex items-center justify-between mb-1.5">
            <label className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Bot Token</label>
            {status && (
              <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${status.tokenSet ? "bg-green-50 text-green-700" : "bg-amber-50 text-amber-700"}`}>
                {status.tokenSet ? "✓ Configured" : "Not set"}
              </span>
            )}
          </div>
          <div className="relative">
            <input
              type={showToken ? "text" : "password"}
              value={botToken}
              onChange={e => setBotToken(e.target.value)}
              placeholder={status?.tokenSet ? "Enter new token to replace existing…" : "Paste token from @BotFather"}
              className="w-full h-10 rounded-xl border border-slate-200 bg-slate-50 px-3 pr-10 text-sm text-slate-800 outline-none focus:border-[#229ED9]"
            />
            <button
              type="button"
              onClick={() => setShowToken(v => !v)}
              className="absolute right-2.5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
            >
              {showToken ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
            </button>
          </div>
          <p className="text-xs text-slate-400 mt-1">Get this from @BotFather on Telegram when you create a bot</p>
        </div>

        <div>
          <div className="flex items-center justify-between mb-1.5">
            <label className="text-xs font-semibold text-slate-600 uppercase tracking-wide">Admin Chat ID</label>
            {status && (
              <span className={`text-xs font-semibold px-2 py-0.5 rounded-full ${status.adminChatIdSet ? "bg-green-50 text-green-700" : "bg-amber-50 text-amber-700"}`}>
                {status.adminChatIdSet ? "✓ Configured" : "Not set"}
              </span>
            )}
          </div>
          <input
            type="text"
            value={adminChatId}
            onChange={e => setAdminChatId(e.target.value)}
            placeholder={status?.adminChatIdSet ? "Enter new chat ID to replace existing…" : "e.g. 123456789"}
            className="w-full h-10 rounded-xl border border-slate-200 bg-slate-50 px-3 text-sm text-slate-800 outline-none focus:border-[#229ED9]"
          />
          <p className="text-xs text-slate-400 mt-1">Your Telegram chat ID — message @userinfobot to find yours</p>
        </div>

        {status && (
          <div className="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2.5 flex items-start gap-2">
            <Globe className="w-3.5 h-3.5 mt-0.5 shrink-0" style={{ color: status.webhookUrl ? "#16A34A" : "#94A3B8" }} />
            <div className="min-w-0">
              <p className="text-xs font-semibold text-slate-600 uppercase tracking-wide mb-0.5">Webhook</p>
              {status.webhookUrl
                ? <p className="text-xs text-green-700 font-medium break-all">{status.webhookUrl}</p>
                : <p className="text-xs text-amber-600 font-medium">Not registered — users cannot link their Telegram accounts</p>
              }
            </div>
          </div>
        )}

        <div className="flex gap-2 pt-1">
          <button
            onClick={save}
            disabled={saving || (!botToken.trim() && !adminChatId.trim())}
            className="flex-1 h-10 rounded-xl text-sm font-bold flex items-center justify-center gap-2 text-white transition-colors disabled:opacity-50"
            style={{ background: saveResult === "ok" ? "#16A34A" : saveResult === "error" ? "#DC2626" : "#229ED9" }}
          >
            {saving
              ? <Loader2 className="w-4 h-4 animate-spin" />
              : saveResult === "ok"
                ? <><Check className="w-4 h-4" /> Saved!</>
                : saveResult === "error"
                  ? "Failed — try again"
                  : <><Save className="w-4 h-4" /> Save</>}
          </button>
          <button
            onClick={test}
            disabled={testing || !status?.tokenSet || !status?.adminChatIdSet}
            className="flex-1 h-10 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-colors disabled:opacity-40"
            style={{ background: "#F1F5F9", color: "#475569" }}
          >
            {testing ? <Loader2 className="w-4 h-4 animate-spin" /> : "Send test message"}
          </button>
        </div>

        <button
          onClick={registerWebhook}
          disabled={registering || !status?.tokenSet}
          className="w-full h-10 rounded-xl text-sm font-bold flex items-center justify-center gap-2 transition-colors disabled:opacity-40"
          style={{ background: "#F1F5F9", color: "#475569" }}
        >
          {registering ? <Loader2 className="w-4 h-4 animate-spin" /> : <><Globe className="w-4 h-4" /> Register Webhook</>}
        </button>

        {testResult && (
          <p className={`text-xs font-medium text-center rounded-lg py-2 px-3 ${testResult.ok ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}>
            {testResult.msg}
          </p>
        )}

        {registerResult && (
          <p className={`text-xs font-medium text-center rounded-lg py-2 px-3 ${registerResult.ok ? "bg-green-50 text-green-700" : "bg-red-50 text-red-700"}`}>
            {registerResult.msg}
          </p>
        )}
      </div>
    </div>
  );
}

