// ─── Discuss Limit Control ────────────────────────────────────
function DiscussLimitControl({ secret }: { secret: string }) {
  const [limit, setLimit] = useState<number | null>(null);
  const [inputVal, setInputVal] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState("");

  useEffect(() => {
    fetch(apiUrl("/admin/discuss-limit"), { headers: { "x-admin-secret": secret } })
      .then(r => r.json())
      .then(d => { setLimit(d.limit); setInputVal(String(d.limit)); })
      .catch(() => { setLimit(5); setInputVal("5"); })
      .finally(() => setLoading(false));
  }, [secret]);

  const save = async () => {
    const val = parseInt(inputVal, 10);
    if (isNaN(val) || val < 0) { setMsg("Enter a valid non-negative number"); return; }
    setSaving(true); setMsg("");
    const res = await fetch(apiUrl("/admin/discuss-limit"), {
      method: "PUT",
      headers: { "Content-Type": "application/json", "x-admin-secret": secret },
      body: JSON.stringify({ limit: val }),
    });
    const data = await res.json();
    if (res.ok) { setLimit(data.limit); setMsg("Saved ✓"); }
    else setMsg(data.error || "Failed to save");
    setSaving(false);
    setTimeout(() => setMsg(""), 3000);
  };

  return (
    <div className="bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100">
      <div className="px-5 py-4 flex items-center gap-2.5" style={{ borderBottom: "1px solid #F1F5F9" }}>
        <MessageSquare className="w-4 h-4 text-orange-500" />
        <div>
          <h2 className="text-sm font-bold text-slate-800">Discuss Message Limit</h2>
          <p className="text-xs text-slate-400 mt-0.5">Global limit for AI discuss messages per account (currently {loading ? "…" : limit}). Per-account overrides take priority.</p>
        </div>
      </div>
      <div className="p-4 flex items-center gap-3">
        {loading ? (
          <Loader2 className="w-4 h-4 animate-spin text-muted-foreground" />
        ) : (
          <>
            <input
              type="number"
              min="0"
              value={inputVal}
              onChange={e => setInputVal(e.target.value)}
              className="w-28 h-9 rounded-lg border border-slate-200 px-3 text-sm focus:outline-none focus:ring-2 focus:ring-orange-400/50"
            />
            <button
              onClick={save}
              disabled={saving}
              className="h-9 px-4 rounded-xl text-xs font-bold text-white flex items-center gap-1.5 transition-colors"
              style={{ background: "#F24908" }}
            >
              {saving ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Save className="w-3.5 h-3.5" />}
              Save
            </button>
            {msg && <p className="text-xs font-semibold text-slate-600">{msg}</p>}
          </>
        )}
      </div>
    </div>
  );
}

// ─── Maintenance Mode Toggle ──────────────────────────────────
function MaintenanceModeToggle({ secret }: { secret: string }) {
  const [enabled, setEnabled] = useState<boolean | null>(null);
  const [loading, setLoading] = useState(true);
  const [toggling, setToggling] = useState(false);
  const [msg, setMsg] = useState("");

  useEffect(() => {
    fetch(apiUrl("/admin/maintenance-mode"), { headers: { "x-admin-secret": secret } })
      .then(r => r.json()).then(d => setEnabled(d.enabled ?? false)).catch(() => setEnabled(false)).finally(() => setLoading(false));
  }, [secret]);

  const toggle = async () => {
    if (enabled === null) return;
    setToggling(true);
    const res = await fetch(apiUrl("/admin/maintenance-mode"), {
      method: "PATCH",
      headers: { "Content-Type": "application/json", "x-admin-secret": secret },
      body: JSON.stringify({ enabled: !enabled }),
    });
    const data = await res.json();
    if (res.ok) { setEnabled(data.enabled); setMsg(data.enabled ? "Maintenance mode enabled" : "Maintenance mode disabled"); }
    else setMsg("Failed to toggle");
    setToggling(false);
    setTimeout(() => setMsg(""), 3000);
  };

  return (
    <div className="bg-white rounded-2xl overflow-hidden shadow-sm border border-slate-100">
      <div className="px-5 py-4 flex items-center gap-2.5" style={{ borderBottom: "1px solid #F1F5F9" }}>
        <AlertCircle className="w-4 h-4 text-red-500" />
        <div>
          <h2 className="text-sm font-bold text-slate-800">Maintenance Mode</h2>
          <p className="text-xs text-slate-400 mt-0.5">When enabled, the app shows a maintenance message to all users</p>
        </div>
      </div>
      <div className="p-4 space-y-3">
        {loading ? (
          <Loader2 className="w-4 h-4 animate-spin text-muted-foreground" />
        ) : (
          <>
            <div className={cn("flex items-center gap-3 p-3 rounded-xl border", enabled ? "bg-red-50 border-red-200" : "bg-green-50 border-green-200")}>
              <div className={cn("w-2.5 h-2.5 rounded-full", enabled ? "bg-red-500 animate-pulse" : "bg-green-500")} />
              <p className={cn("text-sm font-medium", enabled ? "text-red-800" : "text-green-800")}>
                {enabled ? "Maintenance mode is ACTIVE" : "Site is live and operational"}
              </p>
            </div>
            {msg && <p className="text-sm text-muted-foreground font-medium">{msg}</p>}
            <button
              onClick={toggle} disabled={toggling}
              className={cn(
                "w-full h-10 rounded-xl text-sm font-bold flex items-center justify-center gap-2 text-white transition-colors",
                enabled ? "bg-green-600 hover:bg-green-700" : "bg-red-500 hover:bg-red-600",
                toggling && "opacity-60"
              )}
            >
              {toggling ? <Loader2 className="w-4 h-4 animate-spin" /> : enabled ? "Disable Maintenance Mode" : "Enable Maintenance Mode"}
            </button>
          </>
        )}
      </div>
    </div>
  );
}

