  pin_changed: "edit",
  account_password_changed: "edit",
  account_password_set: "edit",
  payment_received: "payment",
  payment_confirmed: "payment",
  payment_failed: "payment",
  payment_test: "payment",
  payment_rejected: "payment",
  admin_login_success: "login",
  admin_login_failed: "login",
  lookup_success: "login",
  lookup_failed: "login",
